    conn.close()

    if not result:
        return "Document not found", 404

    filename = result[0]
    file_path = os.path.join(app.config['UPLOAD_FOLDER'], filename)

    # Run different analysis tools based on the request
    if analysis_type == 'wordcount':
        cmd = f"wc -w {file_path}"
    elif analysis_type == 'linecount':
        cmd = f"wc -l {file_path}"
