from jinja2 import Template
import os

def render_orders(orders):
    # Define the template
    template_string = """
    <!DOCTYPE html>
    <html>
    <head>
        <title>Creative Marketplace Orders</title>
        <meta charset="UTF-8">
        <meta name="viewport" content="width=device-width, initial-scale=1.0">
        <script>
        function downloadResource(resourcePath) {
            fetch('/api/download?file=' + resourcePath)
                .then(response => response.blob())
                .then(blob => {
                    const url = window.URL.createObjectURL(blob);
                    const a = document.createElement('a');
                    a.href = url;
                    a.download = resourcePath.split('/').pop();
                    document.body.appendChild(a);
                    a.click();
                    a.remove();
                });
        }
        </script>
    </head>
    <body>
        <h1>Marketplace Orders</h1>
        <div class="orders-container">
            {% for order in orders %}
            <div class="order-item">
                <h2>{{ order.title }}</h2>
                <p>Seller: {{ order.seller_name }}</p>
                <p>Price: {{ order.price }}</p>
                <div class="description">{{ order.description }}</div>

                {% if order.resource_path %}
                {% set resource_content = get_resource(order.resource_path) %}
                <div class="resource-preview">
                    <h3>Resource Preview:</h3>
                    <pre>{{ resource_content }}</pre>
                    <button onclick="downloadResource('{{ order.resource_path }}')">Download</button>
                </div>
                {% endif %}

                {% if order.image_url %}
                <img src="{{ order.image_url }}" alt="{{ order.title }}" class="item-image">
                {% endif %}
                {% if order.video_url %}
                <video controls>
                    <source src="{{ order.video_url }}" type="video/mp4">
                    Your browser does not support the video tag.
                </video>
                {% endif %}
            </div>
            {% endfor %}
        </div>
    </body>
    </html>
    """

    # Define a function to get resource content that will be accessible in the template
    def get_resource(path):
        with open(path, 'r') as file:
            return file.read()

    # Create template object with custom function
    template = Template(template_string)

    # Make the function available in the template context
    return template.render(orders=orders, get_resource=get_resource)

