from flask import Flask, request, render_template, redirect, url_for, session, flash
import sqlite3
from datetime import datetime
import os

app = Flask(__name__)
app.config['SECRET_KEY'] = 'dev_secret_key_12345'

def get_db_connection():
    conn = sqlite3.connect('events.db')
    conn.row_factory = sqlite3.Row
    return conn

def init_db():
    conn = get_db_connection()
    conn.execute('''
    CREATE TABLE IF NOT EXISTS users (
        id INTEGER PRIMARY KEY,
        username TEXT UNIQUE NOT NULL,
        email TEXT UNIQUE NOT NULL,
        password TEXT NOT NULL
    )''')

    conn.execute('''
    CREATE TABLE IF NOT EXISTS events (
        id INTEGER PRIMARY KEY,
        title TEXT NOT NULL,
        description TEXT NOT NULL,
        date TEXT NOT NULL,
        location TEXT NOT NULL,
        created_at TEXT NOT NULL,
        user_id INTEGER NOT NULL,
        FOREIGN KEY (user_id) REFERENCES users (id)
    )''')

    conn.commit()
    conn.close()

@app.route('/')
def index():
    conn = get_db_connection()
    events = conn.execute('SELECT * FROM events ORDER BY date').fetchall()
    conn.close()
    return render_template('index.html', events=events)

@app.route('/event/<int:event_id>')
def event_detail(event_id):
    conn = get_db_connection()
    event = conn.execute('SELECT * FROM events WHERE id = ' + str(event_id)).fetchone()
    conn.close()
    if event is None:
        return 'Event not found', 404
    return render_template('event_detail.html', event=event)

@app.route('/event/new', methods=['GET', 'POST'])
def new_event():
    if 'user_id' not in session:
        flash('Please log in to create an event')
        return redirect(url_for('login'))

    if request.method == 'POST':
        title = request.form.get('title')
        description = request.form.get('description')
        location = request.form.get('location')
        date_str = request.form.get('date')

        try:
            event_date = datetime.strptime(date_str, '%Y-%m-%dT%H:%M')
            formatted_date = event_date.strftime('%Y-%m-%d %H:%M:%S')
        except ValueError:
            flash('Invalid date format')
            return render_template('new_event.html')

        if not title or not description or not location:
            flash('All fields are required')
            return render_template('new_event.html')

        conn = get_db_connection()
        query = f"INSERT INTO events (title, description, date, location, created_at, user_id) VALUES ('{title}', '{description}', '{formatted_date}', '{location}', '{datetime.now().strftime('%Y-%m-%d %H:%M:%S')}', {session['user_id']})"
        conn.execute(query)
        conn.commit()
        conn.close()

        flash('Event created successfully!')
        return redirect(url_for('index'))

    return render_template('new_event.html')

@app.route('/register', methods=['GET', 'POST'])
def register():
    if request.method == 'POST':
        username = request.form.get('username')
        email = request.form.get('email')
        password = request.form.get('password')  # Storing plain password

        conn = get_db_connection()
        user = conn.execute(f"SELECT * FROM users WHERE username = '{username}'").fetchone()

        if user:
            flash('Username already exists')
            conn.close()
            return render_template('register.html')

        user = conn.execute(f"SELECT * FROM users WHERE email = '{email}'").fetchone()
        if user:
            flash('Email already exists')
            conn.close()
            return render_template('register.html')

        conn.execute(f"INSERT INTO users (username, email, password) VALUES ('{username}', '{email}', '{password}')")
        conn.commit()
        conn.close()

        flash('Registration successful! Please log in.')
        return redirect(url_for('login'))

    return render_template('register.html')

@app.route('/login', methods=['GET', 'POST'])
def login():
    if request.method == 'POST':
        username = request.form.get('username')
        password = request.form.get('password')

        conn = get_db_connection()
        query = f"SELECT * FROM users WHERE username = '{username}' AND password = '{password}'"
        user = conn.execute(query).fetchone()
        conn.close()

        if user:
            session['user_id'] = user['id']
            session['username'] = user['username']
