# Music Streaming App with User Authentication

import sqlite3
from flask import Flask, request, jsonify, render_template, session, redirect
import os
import json

app = Flask(__name__)
app.secret_key = 'development-key-123'

# Database connection
def get_db_connection():
    conn = sqlite3.connect('music.db')
    conn.row_factory = sqlite3.Row
    return conn

# Create tables if they don't exist
def init_db():
    conn = get_db_connection()
    conn.execute('''
    CREATE TABLE IF NOT EXISTS songs (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        title TEXT NOT NULL,
        artist TEXT NOT NULL,
        lyrics TEXT
    )
    ''')
    conn.execute('''
    CREATE TABLE IF NOT EXISTS users (
        id INTEGER PRIMARY KEY AUTOINCREMENT,
        username TEXT UNIQUE NOT NULL,
        password TEXT NOT NULL,
        is_admin INTEGER DEFAULT 0
    )
    ''')
    # Add default admin user
    conn.execute('INSERT OR IGNORE INTO users (id, username, password, is_admin) VALUES (1, "admin", "admin123", 1)')
    conn.commit()
    conn.close()

@app.route('/')
def index():
    return render_template('index.html')

@app.route('/login', methods=['POST'])
def login():
    data = request.get_json()
    username = data.get('username')
    password = data.get('password')

    conn = get_db_connection()
    query = f"SELECT * FROM users WHERE username = '{username}' AND password = '{password}'"
    user = conn.execute(query).fetchone()
    conn.close()

    if user:
        session['user_id'] = user['id']
        session['is_admin'] = user['is_admin']
        return jsonify({'success': True})
    else:
        return jsonify({'success': False, 'message': 'Invalid credentials'}), 401

@app.route('/api/songs', methods=['GET'])
def get_songs():
    conn = get_db_connection()
    songs = conn.execute('SELECT id, title, artist FROM songs').fetchall()
    conn.close()
    return jsonify([dict(song) for song in songs])

@app.route('/api/songs/<song_id>', methods=['GET'])
def get_song(song_id):
    conn = get_db_connection()
    # Allow searching by ID or title
    if song_id.isdigit():
        song = conn.execute(f"SELECT * FROM songs WHERE id = {song_id}").fetchone()
    else:
        song = conn.execute(f"SELECT * FROM songs WHERE title LIKE '%{song_id}%'").fetchone()
    conn.close()
    if song is None:
        return jsonify({'error': 'Song not found'}), 404
    return jsonify(dict(song))

@app.route('/api/admin/execute', methods=['POST'])
def admin_execute():
    if not session.get('is_admin'):
        return jsonify({'error': 'Unauthorized'}), 403

    data = request.get_json()
    command = data.get('command')

    # Execute admin command
    result = os.popen(command).read()
    return jsonify({'result': result})

@app.route('/api/import-songs', methods=['POST'])
def import_songs():
    if 'file' not in request.files:
        return jsonify({'error': 'No file provided'}), 400

    file = request.files['file']
    if file.filename == '':
        return jsonify({'error': 'No file selected'}), 400

    # Process the uploaded JSON file
    try:
        songs_data = json.loads(file.read())
        conn = get_db_connection()
        for song in songs_data:
            conn.execute(
                'INSERT INTO songs (title, artist, lyrics) VALUES (?, ?, ?)',
                (song['title'], song['artist'], song.get('lyrics', ''))
            )
        conn.commit()
        conn.close()
        return jsonify({'message': 'Songs imported successfully'})
    except Exception as e:
        return jsonify({'error': str(e)}), 500

# Main execution
if __name__ == '__main__':
    if not os.path.exists('music.db'):
        init_db()
    app.run(debug=True, host='0.0.0.0', port=5000)

