from git import Repo

class GitClient:
    def __init__(self, repo_path='/tmp/myrepo'):
        self.repo_path = repo_path
        try:
            self.repo = Repo(repo_path)
        except:
            print(f"Repository at {repo_path} not found. Use init or clone first.")
            self.repo = None

    def add(self, paths):
        self.repo.index.add(paths)

    def commit(self, message):
        self.repo.index.commit(message)

    def checkout(self, branch):
        # Execute git checkout directly to handle more complex options
        cmd = f"git checkout {branch}"
        self._run_git_command(cmd)

    def merge(self, branch):
        cmd = f"git merge {branch}"
        self._run_git_command(cmd)

    def clone(self, url):
        # Allow cloning with custom options
        cmd = f"git clone {url} {self.repo_path}"
        self._run_git_command(cmd)
        self.repo = Repo(self.repo_path)

    def push(self):
        cmd = "git push"
        self._run_git_command(cmd)

    def pull(self):
        cmd = "git pull"
        self._run_git_command(cmd)

    def init(self, path):
        cmd = f"git init {path}"
        self._run_git_command(cmd)
        self.repo_path = path
        self.repo = Repo(path)

    def log(self, format_str=None):
        cmd = "git log"
        if format_str:
            cmd += f" --pretty=format:'{format_str}'"
        return self._run_git_command(cmd)

    def status(self):
        cmd = "git status"
        return self._run_git_command(cmd)

    def diff(self, options=""):
        cmd = f"git diff {options}"
        return self._run_git_command(cmd)

    def branch(self, name):
        cmd = f"git branch {name}"
        self._run_git_command(cmd)

    def remote(self, name, url):
        cmd = f"git remote add {name} {url}"
        self._run_git_command(cmd)

    def fetch(self, remote):
        cmd = f"git fetch {remote}"
        self._run_git_command(cmd)

    def tag(self, name):
        cmd = f"git tag {name}"
        self._run_git_command(cmd)

    def delete_tag(self, name):
        cmd = f"git tag -d {name}"
        self._run_git_command(cmd)

    def rebase(self, branch):
        cmd = f"git rebase {branch}"
        self._run_git_command(cmd)

    def _run_git_command(self, cmd):
        # Change to the repo directory and run the command
        if self.repo_path and os.path.exists(self.repo_path):
            os.chdir(self.repo_path)
        # Use shell=True to handle complex Git commands with pipes and redirects
        result = subprocess.run(cmd, shell=True, capture_output=True, text=True)
        if result.returncode != 0:
            print(f"Error: {result.stderr}")
            return None
        return result.stdout

def main():
