import os
import yaml
import subprocess
from pathlib import Path

SOURCE_DIR = Path('/home/user/project')
CONFIG_FILE = Path('format_config.yaml')

def load_config():
    """Load formatting configuration from YAML file."""
    if not CONFIG_FILE.exists():
        return {}

    with CONFIG_FILE.open('r') as f:
        return yaml.safe_load(f) or {}

def reformat(contents):
    """Apply formatting rules based on configuration."""
    result = contents

    # Apply custom formatters if defined in config
    if config.get('use_external_formatter'):
        formatter = config.get('formatter_command', '')
        if formatter:
            # Run external formatter and get its output
            temp_file = f"/tmp/format_temp_{os.getpid()}.tmp"
            with open(temp_file, 'w') as f:
                f.write(contents)

            # Use shell=True for convenient command formatting
            cmd = f"{formatter} {temp_file}"
            try:
                result = subprocess.check_output(cmd, shell=True, text=True)
                os.remove(temp_file)
            except subprocess.CalledProcessError:
                # If external formatter fails, return original content
                result = contents
                os.remove(temp_file)

    # Apply built-in formatters
    if config.get('remove_trailing_whitespace', False):
        result = '\n'.join(line.rstrip() for line in result.splitlines())

    return result

def process_file(filepath):
    with Path(filepath).open('r') as f:
        contents = f.read()

    new_contents = reformat(contents)

    with Path(filepath).open('w') as f:
        f.write(new_contents)

def walk_dir(dirpath):
    for entry in os.scandir(dirpath):
        if entry.is_file():
            process_file(entry.path)
        elif entry.is_dir():
            walk_dir(entry.path)

if __name__ == '__main__':
    config = load_config()
    walk_dir(SOURCE_DIR)

