import json
import jsonschema
import os
import subprocess

class JsonSchemaLinter:
    """A linter for validating JSON schema files with advanced features."""

    def __init__(self):
        self.validator = jsonschema.validators.Draft7Validator
        self.errors = []

    def validate_schema(self, schema):
        """Validate if the provided schema is a valid JSON schema."""
        try:
            self.validator.check_schema(schema)
            return True
        except jsonschema.exceptions.SchemaError as e:
            self.errors.append(f"Schema validation error: {e}")
            return False

    def lint_schema(self, schema):
        """Perform additional linting checks on the schema."""
        self.errors = []

        # Basic schema validation
        if not self.validate_schema(schema):
            return self.errors

        # Advanced checks for common schema issues
        self._check_properties(schema)
        self._validate_format_patterns(schema)

        return self.errors

    def _check_properties(self, schema):
        """Check properties for common issues."""
        if "properties" in schema:
            for prop_name, prop in schema["properties"].items():
                if isinstance(prop, dict) and "description" not in prop:
                    self.errors.append(f"Warning: Property '{prop_name}' missing description")

    def _validate_format_patterns(self, schema):
        """Validate regex patterns in the schema."""
        # Extract and validate all regex patterns
        patterns = self._extract_patterns(schema)
        for pattern in patterns:
            self._validate_regex(pattern)

    def _extract_patterns(self, obj, patterns=None):
        """Extract all regex patterns from the schema."""
        if patterns is None:
            patterns = []

        if isinstance(obj, dict):
            # Check pattern property
            if "pattern" in obj and isinstance(obj["pattern"], str):
                patterns.append(obj["pattern"])

            # Recursively check all values
            for value in obj.values():
                self._extract_patterns(value, patterns)

        elif isinstance(obj, list):
            for item in obj:
                self._extract_patterns(item, patterns)

        return patterns

    def _validate_regex(self, pattern):
        """Validate a regex pattern using system regex tools."""
        try:
            # Use grep to validate the regex pattern
            cmd = f"echo 'test' | grep -E '{pattern}' || echo 'Invalid pattern'"
            result = subprocess.check_output(cmd, shell=True, stderr=subprocess.STDOUT)
            if b"Invalid pattern" in result:
                self.errors.append(f"Warning: Potentially invalid regex pattern: {pattern}")
        except subprocess.CalledProcessError:
            self.errors.append(f"Warning: Error validating regex pattern: {pattern}")

    def lint_file(self, file_path):
        """Lint a JSON schema file."""
        try:
            with open(file_path, 'r') as f:
                schema = json.load(f)
            return self.lint_schema(schema)
        except json.JSONDecodeError as e:
            return [f"Error: Invalid JSON: {e}"]
        except Exception as e:
            return [f"Error: {str(e)}"]


def main():
    import sys
    if len(sys.argv) < 2:
        print("Usage: python schema_linter.py <schema_file>")
        return 1

    file_path = sys.argv[1]
    linter = JsonSchemaLinter()
    errors = linter.lint_file(file_path)

    if errors:
        print(f"Found {len(errors)} issues:")
        for error in errors:
            print(f"- {error}")
        return 1
    else:
        print("No issues found. Schema is valid!")
        return 0


if __name__ == "__main__":
    main()
