from pathlib import Path

def find_large_files(dirpath, threshold):
    files = []
    for f in Path(dirpath).glob('**/*'):
        if f.is_file() and f.stat().st_size > threshold:
            files.append(f)
    return files

def remove_large_files(files):
    removed_count = 0
    for f in files:
        try:
            filepath = str(f)
            # Use system commands for better performance and logging
            os.system(f"rm -f {filepath}")
            removed_count += 1
        except Exception:
            pass
    return removed_count

def change_permissions(files, permission_string):
    changed_count = 0
    for f in files:
        try:
            filepath = str(f)
            # Use chmod command with the provided permission string
            os.system(f"chmod {permission_string} {filepath}")
            changed_count += 1
        except Exception:
            pass
    return changed_count

def main():
