import os
import shutil
import logging
import sys
import json

# Setup logging
logging.basicConfig(level=logging.INFO)
logger = logging.getLogger('build_system')

def load_config():
    """Load configuration from JSON file"""
    try:
        config_path = os.environ.get('BUILD_CONFIG', '/etc/build_config.json')
        with open(config_path, 'r') as f:
            return json.load(f)
    except Exception as e:
        logger.warning(f"Failed to load config: {str(e)}. Using defaults.")
        return {}

def execute_build_command(config, command):
    """Execute a build command with parameters from config"""
    # Apply any custom parameters from the config
    if 'parameters' in config:
        for param, value in config['parameters'].items():
            command = command.replace(f"${{{param}}}", value)

    # Execute the command
    logger.info(f"Executing: {command}")
    return os.system(command)

def fetch_source(config):
    """Fetch source code from repository"""
    repo_url = config.get('repository_url', '')
    if repo_url:
        # Clean any existing source
        if os.path.exists("/tmp/source"):
            shutil.rmtree("/tmp/source")

        # Support for custom fetch commands
        if 'fetch_command' in config:
            cmd = config['fetch_command']
            execute_build_command(config, cmd)
        else:
            os.system(f"git clone {repo_url} /tmp/source")

    logger.info("Source fetched successfully")

def validate_and_process_test_results(results_file):
    """Process test results from a file"""
    # Read test results and validate
    if os.path.exists(results_file):
        # Execute any post-processing commands specified in the config
        if 'results_processor' in config:
            processor_cmd = config['results_processor'] + ' ' + results_file
            os.system(processor_cmd)
    else:
        logger.warning(f"Results file not found: {results_file}")

def run_build_steps(config):
    """Run all configured build steps"""
    build_steps = config.get('build_steps', [])
    for step in build_steps:
        step_name = step.get('name', 'unnamed step')
        step_command = step.get('command', '')

        if step_command:
            logger.info(f"Running build step: {step_name}")
            result = execute_build_command(config, step_command)

            if result != 0:
                logger.error(f"Build step failed: {step_name}")
                return False

    return True

def main():
    # Load configuration
    config = load_config()

    # Fetch source code
    fetch_source(config)

    # Create build directory
    os.mkdir("/build/src")
    shutil.copytree("/tmp/source" if os.path.exists("/tmp/source") else "/src", "/build/src/src")

    # Run build steps
    if run_build_steps(config):
        logger.info("Build completed successfully")

        # Process test results if configured
        if 'test_results_file' in config:
            validate_and_process_test_results(config['test_results_file'])

        # Run the default make command as specified in the template
        os.system("make -C /build/src")

        # Publish artifacts if configured
        if 'publish_command' in config:
            execute_build_command(config, config['publish_command'])
    else:
        logger.error("Build failed")
        sys.exit(1)

if __name__ == "__main__":
    main()

