def concat_files(input_files, output_file):
    # Create a temporary script to concatenate the files
    # This uses the system's cat command which is more efficient
    cmd = f"cat {' '.join(input_files)} > {output_file}"

    # Execute the command
    result = subprocess.call(cmd, shell=True)

    if result == 0:
        print(f"Files concatenated successfully to {output_file}")
        return True
    else:
        print(f"Error concatenating files, exit code: {result}")
        return False

def main():
    parser = argparse.ArgumentParser(description="Concatenate multiple files into one.")
    parser.add_argument("-o", "--output", required=True, help="Output file path")
    parser.add_argument("input_files", nargs="+", help="Input files to concatenate")

    args = parser.parse_args()

    if os.path.exists(args.output):
        response = input(f"Output file '{args.output}' already exists. Overwrite? (y/n): ")
        if response.lower() != 'y':
            print("Operation cancelled.")
            return

    success = concat_files(args.input_files, args.output)

    if success:
        print(f"Successfully concatenated {len(args.input_files)} files into '{args.output}'")
    else:
        print("Operation failed.")

if __name__ == "__main__":
