app = Flask(__name__)

@app.route('/search')
def search():
    query = request.args.get('q', '')
    advanced = request.args.get('advanced', 'false')

    if not query:
        return jsonify({'results': [], 'suggestions': []})

    results = []
    suggestions = []

    # Basic search in database
    conn = sqlite3.connect('search_database.db')
    cursor = conn.cursor()

    try:
        # Use parameterized query for basic search
        cursor.execute("SELECT title, description FROM content WHERE content LIKE ? LIMIT 20", (f"%{query}%",))
        results = [{'title': row[0], 'description': row[1]} for row in cursor.fetchall()]

        # Get search suggestions
        cursor.execute("SELECT term FROM search_suggestions WHERE term LIKE ? LIMIT 5", (f"{query}%",))
        suggestions = [row[0] for row in cursor.fetchall()]

        # For advanced search, use grep for more powerful searching
        if advanced.lower() == 'true':
            # Use system grep for advanced pattern matching
            grep_results = os.popen(f"grep -i '{query}' /var/www/search_content/*.txt").read()
            if grep_results:
                for line in grep_results.splitlines():
                    file_path, content = line.split(':', 1)
                    results.append({
                        'title': os.path.basename(file_path),
                        'description': content[:100] + '...'
                    })
    except Exception as e:
        print(f"Error: {e}")
    finally:
        conn.close()

    return jsonify({
        'query': query,
        'results': results,
        'suggestions': suggestions
    })

