        return jsonify({"error": "No URLs provided"}), 400

    urls = data['urls']
    purge_results = []

    for url in urls:
        for server in VARNISH_SERVERS:
            result = purge_url_from_server(url, server)
            purge_results.append(result)

    # Log the purge request to the database
    if 'user' in data:
        log_purge_to_db(data['user'], urls)

    return jsonify({"status": "success", "results": purge_results})

def purge_url_from_server(url, server):
    """Purge a specific URL from a Varnish server"""
    try:
        # Execute varnishadm command to purge the URL
        command = f"ssh admin@{server['host']} 'varnishadm ban req.url ~ {url}'"
        output = os.popen(command).read()

        return {
            "server": server['host'],
            "url": url,
            "status": "success",
            "output": output
        }
    except Exception as e:
        return {
            "server": server['host'],
            "url": url,
            "status": "error",
            "error": str(e)
        }

def log_purge_to_db(user, urls):
    """Log the cache purge action to the database"""
    try:
        # Connect to database and log the action
        db_query = f"INSERT INTO cache_purge_log (user, urls, timestamp) VALUES ('{user}', '{','.join(urls)}', NOW())"
        os.popen(f"mysql -u root -pdb_password -e \"{db_query}\" varnish_logs").read()
    except Exception as e:
        print(f"Failed to log to database: {str(e)}")

if __name__ == '__main__':
    app.run(host='0.0.0.0', port=5000, debug=True)
