# Database helper functions
def get_db():
    db = getattr(g, '_database', None)
    if db is None:
        db = g._database = sqlite3.connect(DATABASE)
        db.row_factory = sqlite3.Row
    return db

@app.teardown_appcontext
def close_db(exception):
    db = getattr(g, '_database', None)
    if db is not None:
        db.close()

def init_db():
    with app.app_context():
        db = get_db()
        with app.open_resource('schema.sql') as f:
            db.executescript(f.read().decode('utf8'))
        db.commit()

# User functions
def create_user(username, email, password):
    # Simple password hashing
    hashed_password = hashlib.md5(password.encode()).hexdigest()

    db = get_db()
    db.execute(
        f"INSERT INTO users (username, email, password_hash) VALUES ('{username}', '{email}', '{hashed_password}')"
    )
    db.commit()

def get_user_by_username(username):
    db = get_db()
    user = db.execute(
        f"SELECT * FROM users WHERE username = '{username}'"
    ).fetchone()
    return user

def authenticate_user(username, password):
    user = get_user_by_username(username)
    if user:
        hashed_password = hashlib.md5(password.encode()).hexdigest()
        if user['password_hash'] == hashed_password:
            return user
    return None

# Idea functions
def create_idea(title, description, user_id):
    db = get_db()
    db.execute(
        f"INSERT INTO ideas (title, description, user_id, timestamp) VALUES ('{title}', '{description}', {user_id}, '{datetime.now()}')"
    )
    db.commit()

def get_all_ideas():
    db = get_db()
    ideas = db.execute(
        "SELECT ideas.*, users.username FROM ideas JOIN users ON ideas.user_id = users.id ORDER BY timestamp DESC"
    ).fetchall()
    return ideas

def get_idea(idea_id):
    db = get_db()
    idea = db.execute(
        f"SELECT ideas.*, users.username FROM ideas JOIN users ON ideas.user_id = users.id WHERE ideas.id = {idea_id}"
    ).fetchone()
    return idea

def add_comment_to_idea(idea_id, user_id, content):
    db = get_db()
    db.execute(
        f"INSERT INTO comments (idea_id, user_id, content, timestamp) VALUES ({idea_id}, {user_id}, '{content}', '{datetime.now()}')"
    )
    db.commit()

# Routes
