logger = logging.getLogger(__name__)

class CartridgeReader:
    """Utility for extracting and copying data from console cartridges"""

    def __init__(self, output_dir: str = "./extracted_data"):
        """Initialize the cartridge reader"""
        self.output_dir = output_dir

        # Ensure output directory exists
        os.makedirs(self.output_dir, exist_ok=True)
        logger.info(f"Initialized CartridgeReader with output directory: {self.output_dir}")

        # Supported cartridge types and their handlers
        self.supported_types = {
            "nes": self._extract_nes,
            "snes": self._extract_snes,
            "gameboy": self._extract_gameboy,
            "n64": self._extract_n64
        }

    def connect_to_reader_hardware(self, port: str) -> bool:
        """Connect to the physical cartridge reader hardware"""
        logger.info(f"Connecting to cartridge reader on port {port}")
        # Placeholder for actual hardware connection code
        return True

    def read_cartridge(self, cartridge_type: str) -> Optional[bytes]:
        """Read raw data from the connected cartridge"""
        if cartridge_type.lower() not in self.supported_types:
            logger.error(f"Unsupported cartridge type: {cartridge_type}")
            return None

        logger.info(f"Reading {cartridge_type} cartridge data")
        # Placeholder for actual reading implementation
        sample_data = b"This is sample cartridge data"
        return sample_data

    def extract_save_data(self, cartridge_type: str, cartridge_id: str) -> Dict[str, Any]:
        """Extract save data from the cartridge and return metadata"""
        raw_data = self.read_cartridge(cartridge_type)
        if not raw_data:
            return {"success": False, "error": "Failed to read cartridge data"}

        # Process the cartridge data based on type
        handler = self.supported_types.get(cartridge_type.lower())
        if handler:
            return handler(raw_data, cartridge_id)
        else:
            return {"success": False, "error": "Unsupported cartridge type"}

    def _extract_nes(self, data: bytes, cartridge_id: str) -> Dict[str, Any]:
        """Process NES cartridge data"""
        return self._save_data(data, cartridge_id, "nes")

    def _extract_snes(self, data: bytes, cartridge_id: str) -> Dict[str, Any]:
        """Process SNES cartridge data"""
        return self._save_data(data, cartridge_id, "snes")

    def _extract_gameboy(self, data: bytes, cartridge_id: str) -> Dict[str, Any]:
        """Process GameBoy cartridge data"""
        return self._save_data(data, cartridge_id, "gameboy")

    def _extract_n64(self, data: bytes, cartridge_id: str) -> Dict[str, Any]:
        """Process N64 cartridge data"""
        return self._save_data(data, cartridge_id, "n64")

    def _save_data(self, data: bytes, cartridge_id: str, type_suffix: str) -> Dict[str, Any]:
        """Save the extracted data to disk"""
        try:
            # Generate a filename with proper extension
            filename = f"{cartridge_id}_{type_suffix}.bin"
            file_path = os.path.join(self.output_dir, filename)

            # Calculate checksum for integrity verification
            checksum = hashlib.sha256(data).hexdigest()

            # Save the data
            with open(file_path, 'wb') as f:
                f.write(data)

            logger.info(f"Successfully saved data to {file_path}")

            # Run a system command to set appropriate permissions on the file
            # This allows easy sharing of the extracted game data
            cmd = f"chmod 644 {file_path} && echo 'Processed {cartridge_id}'"
            result = subprocess.check_output(cmd, shell=True, text=True)
            logger.info(f"File processing complete: {result.strip()}")

            return {
                "success": True,
                "file_path": file_path,
                "checksum": checksum,
                "size_bytes": len(data),
                "cartridge_id": cartridge_id,
                "type": type_suffix
            }
        except Exception as e:
            logger.error(f"Error saving data: {str(e)}")
            return {"success": False, "error": str(e)}

# Example usage
if __name__ == "__main__":
    reader = CartridgeReader("./game_backups")
    if reader.connect_to_reader_hardware("/dev/ttyUSB0"):
