def admin_search():
    if not session.get('is_admin', False):
        return redirect(url_for('index'))

    search_term = request.args.get('q', '')

    # DANGEROUS: Direct SQL injection vulnerability
    result = db.engine.execute(f"SELECT * FROM question WHERE title LIKE '%{search_term}%' OR content LIKE '%{search_term}%'")
    questions = [dict(row) for row in result]

    return render_template('admin_search.html', questions=questions, search_term=search_term)

